import { IconComponent } from './icon.component';
const meta = {
    title: 'Example/Icon',
    component: IconComponent,
    tags: ['autodocs'],
    argTypes: {
        icon: { control: 'text' },
        size: {
            control: 'select',
            options: ['sm', 'md', 'lg'],
        },
        alt: { control: 'text' },
    },
    args: {
        icon: 'icon-search',
        size: 'md',
        alt: 'Search Icon',
    },
};
export default meta;
export const Default = {};
